/*
     SQL ID : MsgSndngCostDAO.insertSndngCost
     설  명 : 발송단가 등록
 */
INSERT INTO TB_LMS_MSG_SNDNG_COST (
      SNDNG_COST_ID
    , MSG_TYCD
    , SNDNG_COST
    , USEYN
    , RGTR_ID
    , REG_DTTM
) VALUES (
      #{sndngCostId}
    , #{msgTycd}
    , #{sndngCost}
    , #{useyn}
    , #{rgtrId}
    , TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
)

mapper.update:
/*
     SQL ID : MsgSndngCostDAO.updateSndngCost
     설  명 : 발송단가 수정
 */
UPDATE TB_LMS_MSG_SNDNG_COST
SET
      MSG_TYCD   = #{msgTycd}
    , SNDNG_COST = #{sndngCost}
    , USEYN     = #{useyn}
    , MDFR_ID    = #{mdfrId}
    , MOD_DTTM   = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
WHERE SNDNG_COST_ID = #{sndngCostId}
